// JSON response
return ctx.json({ ok: true, data: user });
return ctx.json({ error: "not found" }, { status: 404 });

// HTML response
return ctx.html("<h1>Hello</h1>");

// Plain text
return ctx.text("OK");

// SSR render — renders a JSX VNode
return ctx.render(<MyPage data={data} />);

// Redirect — preserves the SPA partial-nav search param automatically
// for partial requests, so middleware guards keep the SPA navigation flow.
return ctx.redirect("/login");
return ctx.redirect("/dashboard", 301);

// Response headers
ctx.headers.set("X-Request-Id", crypto.randomUUID());
ctx.headers.append("Vary", "Accept-Encoding");

// Cookies
ctx.cookies.set("session", token, { httpOnly: true, maxAge: 3600 });
const session = ctx.cookies.get("session");
ctx.cookies.delete("session");
const all = ctx.cookies.all(); // Record<string, string>

return ctx.stream(async (write) => {
  for await (const chunk of fileStream) {
    await write(chunk);
  }
}, { headers: { "Content-Type": "application/octet-stream" } });

import { HttpError } from "@hushkey/howl";

app.get("/secret", (ctx) => {
  if (!ctx.state.userContext) throw new HttpError(401);   // → "Unauthorized"
  throw new HttpError(404, "No such secret");             // → "No such secret"
});

// With cause for log enrichment
try {
  await db.fetch(id);
} catch (e) {
  throw new HttpError(500, "Database unavailable", { cause: e });
}

app.use(async (ctx) => {
  const start = Date.now();
  const response = await ctx.next();
  const ms = Date.now() - start;
  response.headers.set("X-Response-Time", `${ms}ms`);
  return response;
});
